body {
  margin: 0px;
}

.container {
  font-family: "Inter", "Segoe UI", Arial, sans-serif;
  width: 100%;
}

.info-grid {
  display: flex;
  gap: 40px;
  background: #f2f3f5;
  border-radius: 5px;
  padding: 20px;
}

.info-column {
  width: 60%;
}

.info-row {
  display: flex;
  justify-content: space-between;
  padding: 6px 0;
}

.label {
  font-weight: 500;
  color: #222;
}

.value {
  font-weight: 600;
  color: #111;
  text-align: right;
}

.value:empty::after {
  content: "-";
  color: #aaa;
}

