import React from "https://esm.sh/react@18.2.0";
import ReactDOM from "https://esm.sh/react-dom@18.2.0";

function App() {
  // ✅ Get data dynamically from Appsmith live model
  const data = appsmith.model?.data || {};

  const infoLeft = [
    { label: "Invoice Number", value: data.invoice_number || "-" },
    { label: "Bill Source", value: data.bill_source || "-" },
    { label: "Date Bill Received", value: data.received_on || "-" },
    { label: "Date Loaded", value: data.loaded_date || "-" },
    { label: "Date Marked for Payment", value: data.marked_for_payment || "-" },
    { label: "Date Fund Request Sent by A/P File", value: data.date_fund_request_sent || "-" },
  ];

  const infoRight = [];

  return (
    <div className="container">
      <div className="info-grid">
        <div className="info-column">
          {infoLeft.map((item) => (
            <div className="info-row" key={item.label}>
              <span className="label">{item.label}</span>
              <span className="value">{item.value}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
